.chart-container {
  max-width: 900px; /* to hơn */
  margin: 0 auto;
  padding: 30px;
  background: #fff;
  border-radius: 16px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.1);
}

h2 {
  text-align: center;
  margin-bottom: 24px;
  font-size: 28px;
  font-weight: bold;
  color: #333;
}

select {
  width: 100%;
  margin-bottom: 30px;
  padding: 12px 16px;
  font-size: 18px;
  border: 1px solid #ddd;
  border-radius: 8px;
  background-color: #f9f9f9;
  transition: all 0.2s ease;
  outline: none;

  &:hover {
    border-color: #4CAF50;
    background-color: #fff;
  }

  &:focus {
    border-color: #4CAF50;
    box-shadow: 0 0 0 3px rgba(76, 175, 80, 0.2);
    background-color: #fff;
  }
}

.chart-wrapper {
  height: 500px; /* to hơn */
}
